"use strict";(globalThis.webpackChunkdocusaurus_site=globalThis.webpackChunkdocusaurus_site||[]).push([[34769],{29420(e,n,r){r.r(n),r.d(n,{assets:()=>s,contentTitle:()=>l,default:()=>c,frontMatter:()=>t,metadata:()=>i,toc:()=>u});const i=JSON.parse('{"id":"Examples/General/MbufColor/CPP","title":"MbufColor","description":"This example demonstrates color buffer manipulations. It first loads a color image and adds color annotations. If image processing is available, it converts the image to Hue, Luminance and Saturation (HLS), adds a certain offset to the luminance component and converts the image back to Red, Green, Blue (RGB) to display the result.","source":"@site/docs/Examples/General/MbufColor/CPP.md","sourceDirName":"Examples/General/MbufColor","slug":"/Examples/General/MbufColor/CPP","permalink":"/DOC_PUBLIC_AIL11_MD_HELP_SOURCE/Examples/General/MbufColor/CPP","draft":false,"unlisted":false,"tags":[],"version":"current","frontMatter":{"title":"MbufColor","description":"This example demonstrates color buffer manipulations. It first loads a color image and adds color annotations. If image processing is available, it converts the image to Hue, Luminance and Saturation (HLS), adds a certain offset to the luminance component and converts the image back to Red, Green, Blue (RGB) to display the result.","ms.language":"C++"},"sidebar":"examplesSidebar","previous":{"title":"Mblob","permalink":"/DOC_PUBLIC_AIL11_MD_HELP_SOURCE/Examples/General/Mblob/Python"},"next":{"title":"MbufColor","permalink":"/DOC_PUBLIC_AIL11_MD_HELP_SOURCE/Examples/General/MbufColor/CPP_Object"}}');var a=r(74848),o=r(28453);const t={title:"MbufColor",description:"This example demonstrates color buffer manipulations. It first loads a color image and adds color annotations. If image processing is available, it converts the image to Hue, Luminance and Saturation (HLS), adds a certain offset to the luminance component and converts the image back to Red, Green, Blue (RGB) to display the result.","ms.language":"C++"},l="MbufColor",s={},u=[];function d(e){const n={blockquote:"blockquote",code:"code",h1:"h1",header:"header",p:"p",pre:"pre",strong:"strong",...(0,o.R)(),...e.components};return(0,a.jsxs)(a.Fragment,{children:[(0,a.jsx)(n.header,{children:(0,a.jsx)(n.h1,{id:"mbufcolor",children:"MbufColor"})}),"\n",(0,a.jsxs)(n.blockquote,{children:["\n",(0,a.jsx)(n.p,{children:"This example demonstrates color buffer manipulations. It first loads a color image and adds color annotations. If image processing is available, it converts the image to Hue, Luminance and Saturation (HLS), adds a certain offset to the luminance component and converts the image back to Red, Green, Blue (RGB) to display the result."}),"\n"]}),"\n",(0,a.jsxs)(n.p,{children:[(0,a.jsx)(n.strong,{children:"Language:"})," C++"]}),"\n",(0,a.jsxs)(n.p,{children:[(0,a.jsx)(n.strong,{children:"Functions used:"})," ",(0,a.jsx)(n.code,{children:"MdispFree"}),", ",(0,a.jsx)(n.code,{children:"MappAlloc"}),", ",(0,a.jsx)(n.code,{children:"MappFree"}),", ",(0,a.jsx)(n.code,{children:"MbufAllocColor"}),", ",(0,a.jsx)(n.code,{children:"MbufChild2d"}),", ",(0,a.jsx)(n.code,{children:"MbufChildColor"}),", ",(0,a.jsx)(n.code,{children:"MbufClear"}),", ",(0,a.jsx)(n.code,{children:"MbufDiskInquire"}),", ",(0,a.jsx)(n.code,{children:"MbufFree"}),", ",(0,a.jsx)(n.code,{children:"MbufLoad"}),", ",(0,a.jsx)(n.code,{children:"MdispAlloc"}),", ",(0,a.jsx)(n.code,{children:"MdispSelect"}),", ",(0,a.jsx)(n.code,{children:"MgraText"}),", ",(0,a.jsx)(n.code,{children:"MimArith"}),", ",(0,a.jsx)(n.code,{children:"MimConvert"}),", ",(0,a.jsx)(n.code,{children:"MsysAlloc"}),", ",(0,a.jsx)(n.code,{children:"MsysFree"})]}),"\n",(0,a.jsxs)(n.p,{children:[(0,a.jsx)(n.strong,{children:"Categories:"})," Overview, General, Industries, Applications, Preprocessing, Modules, Buffer, Display, Graphics, Image Processing, What's New, Older"]}),"\n",(0,a.jsx)(n.pre,{children:(0,a.jsx)(n.code,{className:"language-cpp",children:'///////////////////////////////////////////////////////////////////////////////\r\n// Aurora Imaging Library\r\n// Filename:    MBufColor.cpp\r\n//\r\n// Description: This program demonstrates color buffer manipulations. It allocates \r\n//              a displayable color image buffer, displays it, and loads a color   \r\n//              image into the left part. After that, color annotations are done \r\n//              in each band of the color buffer. Finally, to increase the image\r\n//              luminance, the image is converted to Hue, Saturation and Luminance\r\n//              (HSL), a certain offset is added to the luminance component and \r\n//              the image is converted back to Red, Green, Blue (RGB) into the \r\n//              right part to display the result. \r\n//           \r\n//              The example also demonstrates how to display multiple images \r\n//              in a single display using child buffers.\r\n//\r\n// (C) 1992-2026 Zebra Technologies Corp. and/or its affiliates\r\n// All Rights Reserved\r\n///////////////////////////////////////////////////////////////////////////////\r\n\r\n#include <AIL.h> \r\n\r\n// Source image file specifications.  \r\n#define IMAGE_FILE              M_IMAGE_PATH AIL_TEXT("Bird.mim")\r\n\r\n// Luminance offset to add to the image. \r\n#define IMAGE_LUMINANCE_OFFSET  40L\r\n\r\n// Main function. \r\nint MosMain(void)\r\n{ \r\n   AIL_ID  AilApplication,       // Application identifier.\r\n           AilSystem,            // System identifier.     \r\n           AilDisplay,           // Display identifier.    \r\n           AilImage,             // Image buffer identifier.\r\n           AilLeftSubImage,      // Sub-image buffer identifier for original image. \r\n           AilRightSubImage,     // Sub-image buffer identifier for processed image.\r\n           AilLumSubImage=0,     // Sub-image buffer identifier for luminance.      \r\n           AilRedBandSubImage,   // Sub-image buffer identifier for red component.  \r\n           AilGreenBandSubImage, // Sub-image buffer identifier for green component.\r\n           AilBlueBandSubImage;  // Sub-image buffer identifier for blue component. \r\n   AIL_INT SizeX, SizeY, SizeBand, Type;\r\n\r\n   // Allocate defaults. \r\n   MappAllocDefault(M_DEFAULT, &AilApplication, &AilSystem, &AilDisplay, M_NULL, M_NULL);\r\n\r\n   // Allocate a color display buffer twice the size of the source image and display it. \r\n   MbufAllocColor(AilSystem,\r\n                  MbufDiskInquire(IMAGE_FILE, M_SIZE_BAND, &SizeBand),\r\n                  MbufDiskInquire(IMAGE_FILE, M_SIZE_X, &SizeX) * 2,\r\n                  MbufDiskInquire(IMAGE_FILE, M_SIZE_Y, &SizeY),\r\n                  MbufDiskInquire(IMAGE_FILE, M_TYPE,   &Type),\r\n                  M_IMAGE+M_DISP+M_PROC, &AilImage);\r\n   MbufClear(AilImage, 0L);\r\n   MdispSelect(AilDisplay, AilImage);\r\n\r\n   // Define 2 child buffers that maps to the left and right part of the display \r\n   // buffer, to put the source and destination color images.\r\n   MbufChild2d(AilImage, 0L, 0L, SizeX, SizeY, &AilLeftSubImage);\r\n   MbufChild2d(AilImage, SizeX, 0L, SizeX, SizeY, &AilRightSubImage);\r\n\r\n   // Load the color source image on the left. \r\n   MbufLoad(IMAGE_FILE, AilLeftSubImage);\r\n      \r\n   // Define child buffers that map to the red, green and blue components\r\n   // of the source image.\r\n   MbufChildColor(AilLeftSubImage, M_RED,   &AilRedBandSubImage);\r\n   MbufChildColor(AilLeftSubImage, M_GREEN, &AilGreenBandSubImage);\r\n   MbufChildColor(AilLeftSubImage, M_BLUE,  &AilBlueBandSubImage);\r\n\r\n   // Write color text annotations to show access in each individual band of the image.\r\n\r\n   // Note that this is typically done more simply by using:\r\n   // MgraControl(M_DEFAULT, M_COLOR, M_RGB888(0xFF,0x90,0x00));\r\n   // MgraText(M_DEFAULT, AilLeftSubImage, ...);\r\n   MgraControl(M_DEFAULT, M_COLOR, 0xFF);\r\n   MgraText(M_DEFAULT, AilRedBandSubImage,   SizeX/16, SizeY/8, AIL_TEXT(" TOUCAN "));\r\n   MgraControl(M_DEFAULT, M_COLOR, 0x90);\r\n   MgraText(M_DEFAULT, AilGreenBandSubImage, SizeX/16, SizeY/8, AIL_TEXT(" TOUCAN "));\r\n   MgraControl(M_DEFAULT, M_COLOR, 0x00);\r\n   MgraText(M_DEFAULT, AilBlueBandSubImage,  SizeX/16, SizeY/8, AIL_TEXT(" TOUCAN "));\r\n \r\n   // Print a message. \r\n   MosPrintf(AIL_TEXT("\\nCOLOR OPERATIONS:\\n"));\r\n   MosPrintf(AIL_TEXT("-----------------\\n\\n"));\r\n   MosPrintf(AIL_TEXT("A color source image was loaded on the left and color text\\n"));\r\n   MosPrintf(AIL_TEXT("annotations were written in it.\\n"));\r\n   MosPrintf(AIL_TEXT("Press any key to continue.\\n\\n"));\r\n   MosGetch();\r\n\r\n   // Convert image to Hue, Saturation, Luminance color space (HSL). \r\n   MimConvert(AilLeftSubImage, AilRightSubImage, M_RGB_TO_HSL);\r\n  \r\n   // Create a child buffer that maps to the luminance component. \r\n   MbufChildColor(AilRightSubImage, M_LUMINANCE, &AilLumSubImage);\r\n     \r\n   // Add an offset to the luminance component. \r\n   MimArith(AilLumSubImage, IMAGE_LUMINANCE_OFFSET, AilLumSubImage, \r\n                                                      M_ADD_CONST+M_SATURATION);\r\n  \r\n   // Convert image back to Red, Green, Blue color space (RGB) for display. \r\n   MimConvert(AilRightSubImage, AilRightSubImage, M_HSL_TO_RGB); \r\n\r\n   // Print a message. \r\n   MosPrintf(AIL_TEXT("Luminance was increased using color image processing.\\n"));\r\n  \r\n   // Print a message. \r\n   MosPrintf(AIL_TEXT("Press any key to end.\\n"));\r\n   MosGetch();\r\n\r\n   // Release sub-images and color image buffer. \r\n   MbufFree(AilLumSubImage);\r\n   MbufFree(AilRedBandSubImage);\r\n   MbufFree(AilGreenBandSubImage);\r\n   MbufFree(AilBlueBandSubImage);\r\n   MbufFree(AilRightSubImage);\r\n   MbufFree(AilLeftSubImage);\r\n   MbufFree(AilImage);\r\n\r\n   // Release defaults. \r\n   MappFreeDefault(AilApplication, AilSystem, AilDisplay, M_NULL, M_NULL);\r\n\r\n   return 0;\r\n}\r\n\r\n\n'})})]})}function c(e={}){const{wrapper:n}={...(0,o.R)(),...e.components};return n?(0,a.jsx)(n,{...e,children:(0,a.jsx)(d,{...e})}):d(e)}},28453(e,n,r){r.d(n,{R:()=>t,x:()=>l});var i=r(96540);const a={},o=i.createContext(a);function t(e){const n=i.useContext(o);return i.useMemo(function(){return"function"==typeof e?e(n):{...n,...e}},[n,e])}function l(e){let n;return n=e.disableParentContext?"function"==typeof e.components?e.components(a):e.components||a:t(e.components),i.createElement(o.Provider,{value:n},e.children)}}}]);